import React, { useState, useMemo } from 'react';
import { Button, Input, Modal, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { masterService } from '../../../services/master/masterService';
import type { TransferTemplateDto } from '../../../services/master/models';
import { normalizeCode } from '../../../utils/codeField';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';

import { CatalogCompanyTh, CatalogCompanyTd, CatalogCompanyField } from '../../../components/catalog';
import styles from '../../../styles/erpPage.module.css';

const TEST_ID = 'dm-ket-chuyen';

type FormErrors = Partial<Record<'code' | 'name' | 'debitAccountCode' | 'creditAccountCode', string>>;

const KetChuyenPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [items, setItems] = useState<TransferTemplateDto[]>([]);
  const sessionCompanyName = useMemo(() => items[0]?.companyName, [items]);
  const [loading, setLoading] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<TransferTemplateDto | null>(null);
  const [form, setForm] = useState<Partial<TransferTemplateDto>>({});
  const [errors, setErrors] = useState<FormErrors>({});
  const [saving, setSaving] = useState(false);
  const [deleteId, setDeleteId] = useState<string | null>(null);
  const [reloadKey, setReloadKey] = useState(0);

  const handleSearch = () => setSearch(searchDraft.trim());
  const refresh = () => setReloadKey(k => k + 1);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      masterService.getTransferTemplates({ search: search || undefined })
        .then(data => { if (!cancelled) setItems(data); })
        .catch(err => {
          if (!cancelled) dispatch(addToast({ message: err?.message ?? 'Lỗi tải mẫu kết chuyển', type: 'error' }));
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [search, reloadKey, dispatch]);

  const clearFieldError = (key: keyof FormErrors) => {
    setErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const validate = (): FormErrors => {
    const next: FormErrors = {};
    if (!form.code?.trim()) next.code = 'Nhập mã mẫu kết chuyển';
    if (!form.name?.trim()) next.name = 'Nhập tên mẫu kết chuyển';
    if (!form.debitAccountCode?.trim()) next.debitAccountCode = 'Nhập TK Nợ';
    if (!form.creditAccountCode?.trim()) next.creditAccountCode = 'Nhập TK Có';
    return next;
  };

  const openAdd = () => {
    setEditing(null);
    setForm({});
    setErrors({});
    setModalOpen(true);
  };

  const openEdit = (row: TransferTemplateDto) => {
    setEditing(row);
    setForm({ ...row });
    setErrors({});
    setModalOpen(true);
  };

  const handleSave = async () => {
    const nextErrors = validate();
    if (Object.keys(nextErrors).length > 0) {
      setErrors(nextErrors);
      scrollToFirstFieldError(TEST_ID);
      return;
    }
    setSaving(true);
    try {
      if (editing) await masterService.updateTransferTemplate(editing.id, form);
      else await masterService.createTransferTemplate(form);
      dispatch(addToast({ message: editing ? 'Cập nhật mẫu kết chuyển thành công' : 'Tạo mẫu kết chuyển thành công', type: 'success' }));
      setModalOpen(false);
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' }));
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (id: string) => {
    try {
      await masterService.deleteTransferTemplate(id);
      dispatch(addToast({ message: 'Xóa mẫu kết chuyển thành công', type: 'success' }));
      setDeleteId(null);
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Xóa thất bại', type: 'error' }));
    }
  };

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-random" /> Mẫu kết chuyển</h1>
        </div>
        <div className={styles.headerActions}>
          <Button variant="primary" onClick={openAdd} data-testid={`${TEST_ID}-add-btn`}>
            <i className="fas fa-plus" /> Thêm mẫu
          </Button>
        </div>
      </div>

      <div className={styles.filtersBar} data-testid={`${TEST_ID}-filters`}>
        <div className={styles.field} data-testid={`${TEST_ID}-field-search`}>
          <Input
            placeholder="Tìm mã, tên..."
            value={searchDraft}
            onChange={e => setSearchDraft(e.target.value)}
            onKeyDown={e => { if (e.key === 'Enter') handleSearch(); }}
          />
        </div>
        <Button
          variant="secondary"
          onClick={handleSearch}
          aria-label="Tìm kiếm"
          data-testid={`${TEST_ID}-search-btn`}
        >
          <i className="fas fa-search" />
        </Button>
        <Button
          variant="secondary"
          onClick={refresh}
          aria-label="Làm mới"
          data-testid={`${TEST_ID}-refresh-btn`}
        >
          <i className="fas fa-sync" />
        </Button>
      </div>

      <div className={styles.tableCard}>
        {loading ? (
          <div className={styles.loading}><i className="fas fa-spinner fa-spin" /> Đang tải...</div>
        ) : items.length === 0 ? (
          <div className={styles.empty}>
            <i className="fas fa-inbox" />
            <p>{search.trim() ? 'Không tìm thấy mẫu phù hợp' : 'Không có dữ liệu'}</p>
          </div>
        ) : (
          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Mã</th>
                  <th>Tên</th>
                  <th>TK Nợ</th>
                  <th>TK Có</th>
                  <CatalogCompanyTh />
                  <th className={styles.colActions} />
                </tr>
              </thead>
              <tbody>
                {items.map(r => (
                  <tr key={r.id}>
                    <td><code>{r.code}</code></td>
                    <td>{r.name}</td>
                    <td><code>{r.debitAccountCode}</code></td>
                    <td><code>{r.creditAccountCode}</code></td>
                    <CatalogCompanyTd label={r.companyName} />
                    <td className={styles.colActions}>
                      <button type="button" className={styles.actionBtn} onClick={() => openEdit(r)} title="Sửa">
                        <i className="fas fa-edit" />
                      </button>
                      <button type="button" className={`${styles.actionBtn} ${styles.actionBtnDanger}`} onClick={() => setDeleteId(r.id)} title="Xóa">
                        <i className="fas fa-trash" />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      <Modal isOpen={modalOpen} onClose={() => setModalOpen(false)} title={editing ? 'Sửa mẫu kết chuyển' : 'Thêm mẫu kết chuyển'}>
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form`}>
          <div className={styles.formGrid}>
            <div className={styles.masterCodeNameRow}>
              <div className={styles.field} data-testid={`${TEST_ID}-field-code`}>
                <label className={styles.label}>Mã *</label>
                <Input
                  value={form.code ?? ''}
                  disabled={!!editing}
                  error={errors.code}
                  className={styles.codeInput}
                  onChange={e => {
                    clearFieldError('code');
                    setForm(f => ({ ...f, code: normalizeCode(e.target.value) }));
                  }}
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-name`}>
                <label className={styles.label}>Tên *</label>
                <Input
                  value={form.name ?? ''}
                  error={errors.name}
                  onChange={e => {
                    clearFieldError('name');
                    setForm(f => ({ ...f, name: e.target.value }));
                  }}
                />
              </div>
            </div>
            <div className={styles.masterCodeNameRow}>
              <div className={styles.field} data-testid={`${TEST_ID}-field-debitAccountCode`}>
                <label className={styles.label}>TK Nợ *</label>
                <Input
                  value={form.debitAccountCode ?? ''}
                  error={errors.debitAccountCode}
                  placeholder="911..."
                  onChange={e => {
                    clearFieldError('debitAccountCode');
                    setForm(f => ({ ...f, debitAccountCode: e.target.value }));
                  }}
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-creditAccountCode`}>
                <label className={styles.label}>TK Có *</label>
                <Input
                  value={form.creditAccountCode ?? ''}
                  error={errors.creditAccountCode}
                  placeholder="421..."
                  onChange={e => {
                    clearFieldError('creditAccountCode');
                    setForm(f => ({ ...f, creditAccountCode: e.target.value }));
                  }}
                />
              </div>
            </div>
          </div>
          <CatalogCompanyField
            testIdPrefix={TEST_ID}
            companyName={editing?.companyName ?? sessionCompanyName}
          />
          <div className={styles.modalActions}>
            <Button variant="secondary" onClick={() => setModalOpen(false)}>Hủy</Button>
            <Button variant="primary" onClick={handleSave} disabled={saving} data-testid={`${TEST_ID}-save-btn`}>
              {saving ? 'Đang lưu...' : 'Lưu'}
            </Button>
          </div>
        </div>
      </Modal>

      <Modal isOpen={deleteId != null} onClose={() => setDeleteId(null)} title="Xác nhận xóa">
        <p>Bạn có chắc muốn xóa mẫu kết chuyển này?</p>
        <div className={styles.modalActions}>
          <Button variant="secondary" onClick={() => setDeleteId(null)}>Hủy</Button>
          <Button variant="primary" onClick={() => deleteId != null && handleDelete(deleteId)}>Xóa</Button>
        </div>
      </Modal>
    </div>
  );
};

export default KetChuyenPage;
